89→
90→    /* --version: print and exit 0 immediately. */
91→    if (cli.version) {
92→        print_version();
93→        return 0;
94→    }
95→
96→    /* --help: print and exit 0 immediately. */
97→    if (cli.help) {
98→        print_help();
99→        return 0;
100→    }
101→
102→    /* Determine shell mode. */
103→    ShellMode mode;
104→    if (cli.command) {
105→        mode = SHELL_MODE_C_MODE;
106→    } else if (cli.script) {
107→        mode = SHELL_MODE_SCRIPT;
108→    } else if (isatty(STDIN_FILENO)) {
109→        mode = cli.login ? SHELL_MODE_INTERACTIVE_LOGIN : SHELL_MODE_INTERACTIVE_NON_LOGIN;
110→    } else {
111→        mode = SHELL_MODE_STDIN_BATCH;
112→    }
