37→        if (strncmp(s, "&&", 2) == 0) { *out_kind = TOKEN_AND; return 1; }
38→        if (strncmp(s, ">>", 2) == 0) { *out_kind = TOKEN_REDIRECT_APPEND; return 1; }
39→        if (strncmp(s, "<<", 2) == 0) { *out_kind = TOKEN_REDIRECT_HEREDOC; return 1; }
40→    }
41→    if (len == 1) {
42→        if (s[0] == '|') { *out_kind = TOKEN_PIPE; return 1; }
43→        if (s[0] == '>') { *out_kind = TOKEN_REDIRECT_GT; return 1; }
44→        if (s[0] == '<') { *out_kind = TOKEN_REDIRECT_LT; return 1; }
45→        if (s[0] == ';') { *out_kind = TOKEN_SEMI; return 1; }
46→    }
47→    return 0;
48→}
