50→static void emit_error(Lexer *lx, const char *msg)
51→{
52→    lx->error = 1;
53→    lx->err_msg = agenc_strdup(msg);
54→}
55→
56→Lexer *lexer_create(ShellState *ss, const char *input, size_t len)
57→{
58→    if (!ss || !input) return NULL;
59→    Lexer *lx = agenc_alloc(sizeof(Lexer));
60→    memset(lx, 0, sizeof(*lx));
61→    lx->ss = ss;
62→    lx->input = input;
63→    lx->input_len = len;
64→    lx->line_no = 1;
65→    return lx;
66→}
67→
68→void lexer_destroy(Lexer *lx)
69→{
70→    if (!lx) return;
71→    if (lx->err_msg) agenc_free(lx->err_msg);
72→    if (lx->err_detail) agenc_free(lx->err_detail);
73→    agenc_free(lx);
74→}
75→
76→const char *lexer_get_error(const Lexer *lx)
77→{
78→    return lx && lx->err_msg ? lx->err_msg : "unknown lex error";
79→}
80→
81→void lexer_free_token(Token *t)
82→{
83→    if (t && t->lexeme) { agenc_free(t->lexeme); t->lexeme = NULL; }
84→}
85→
86→static void skip_whitespace(Lexer *lx)
87→{
88→    while (lx->pos < lx->input_len && isspace((unsigned char)lx->input[lx->pos])) {
89→        if (lx->input[lx->pos] == '\n') lx->line_no++;
90→        lx->pos++;
91→    }
92→}
93→
94→static TokenKind parse_single_quoted(Lexer *lx, size_t *out_start)
95→{
96→    size_t cs = lx->pos + 1;
97→    *out_start = cs;
98→    lx->pos++;
99→    while (lx->pos < lx->input_len && lx->input[lx->pos] != '\'') {
100→        if (lx->input[lx->pos] == '\\') { lx->pos++; if (lx->pos >= lx->input_len) break; }
101→        lx->pos++;
102→    }
103→    if (lx->pos >= lx->input_len) { emit_error(lx, "unterminated quote"); return TOKEN_ERROR; }
104→    lx->pos++;
105→    size_t clen = lx->pos - cs - 1;
106→    TokenKind k;
107→    if (is_operator_str(lx->input + cs, clen, &k)) return k;
108→    return TOKEN_WORD;
109→}
110→
111→int lexer_next(Lexer *lx, Token *out)
112→{
113→    if (!lx || !out) return -2;
114→    memset(out, 0, sizeof(*out));
115→    skip_whitespace(lx);
116→
117→    if (lx->pos >= lx->input_len) {
118→        out->kind = TOKEN_EOF;
119→        out->loc.line = lx->line_no;
120→        out->loc.col = (int)lx->pos;
121→        return -1;
122→    }
123→
124→    out->loc.line = lx->line_no;
125→    out->loc.col = (int)lx->pos;
126→    const char *start = lx->input + lx->pos;
127→    size_t start_pos = lx->pos;
128→
129→    /* 3-char operators. */
130→    if (lx->pos + 2 < lx->input_len) {
131→        if (lx->input[lx->pos] == '<' && lx->input[lx->pos+1] == '<' && lx->input[lx->pos+2] == '-') {
132→            out->kind = TOKEN_REDIRECT_HEREDOC_STRIP; lx->pos += 3; goto done;
133→        }
134→        if (lx->input[lx->pos] == '<' && lx->input[lx->pos+1] == '<' && lx->input[lx->pos+2] == '<') {
135→            out->kind = TOKEN_REDIRECT_HERESTRING; lx->pos += 3; goto done;
136→        }
137→    }
138→    /* 2-char operators. */
139→    if (lx->pos + 1 < lx->input_len) {
140→        char a = lx->input[lx->pos], b = lx->input[lx->pos+1];
141→        if (a == '&' && b == '&') { out->kind = TOKEN_AND; lx->pos += 2; goto done; }
142→        if (a == '|' && b == '|') { out->kind = TOKEN_OR; lx->pos += 2; goto done; }
143→        if (a == '>' && b == '>') { out->kind = TOKEN_REDIRECT_APPEND; lx->pos += 2; goto done; }
144→        if (a == '<' && b == '<') { out->kind = TOKEN_REDIRECT_HEREDOC; lx->pos += 2; goto done; }
145→        if (a == '>' && b == '|') { out->kind = TOKEN_REDIRECT_NCLOBBER; lx->pos += 2; goto done; }
146→        if (a == '<' && b == '>') { out->kind = TOKEN_REDIRECT_OPEN_DUP; lx->pos += 2; goto done; }
147→    }
148→    /* ;; two SEMI. */
149→    if (lx->pos + 1 < lx->input_len && lx->input[lx->pos] == ';' && lx->input[lx->pos+1] == ';') {
150→        out->kind = TOKEN_SEMI; lx->pos++; goto done;
151→    }
152→
153→    char c = lx->input[lx->pos];
154→    if (c == ';')       { out->kind = TOKEN_SEMI; lx->pos++; goto done; }
155→    if (c == '&')       { out->kind = TOKEN_WORD; lx->pos++; goto done; }
156→    if (c == '|')       { out->kind = TOKEN_PIPE; lx->pos++; goto done; }
157→    if (c == '>')       { out->kind = TOKEN_REDIRECT_GT; lx->pos++; goto done; }
158→    if (c == '<')       { out->kind = TOKEN_REDIRECT_LT; lx->pos++; goto done; }
159→    if (c == '(')       { out->kind = TOKEN_GROUP_OPEN; lx->pos++; goto done; }
160→    if (c == ')')       { out->kind = TOKEN_GROUP_CLOSE; lx->pos++; goto done; }
161→    if (c == '!')       { out->kind = TOKEN_NEGATE; lx->pos++; goto done; }
162→
163→    /* Single-quoted string. */
164→    if (c == '\'') {
165→        out->kind = parse_single_quoted(lx, &start_pos);
166→        lx->pos--;
167→        start = lx->input + start_pos;
168→        out->flags |= TOKEN_FLAG_QUOTED;
169→        if (out->kind == TOKEN_ERROR) { lx->pos++; return -2; }
170→        goto done;
171→    }
172→    /* Double-quoted string. */
173→    if (c == '"') {
174→        start_pos++;
175→        start = lx->input + start_pos;
176→        out->kind = TOKEN_WORD;
177→        out->flags |= TOKEN_FLAG_QUOTED;
178→        lx->pos++;
179→        while (lx->pos < lx->input_len && lx->input[lx->pos] != '"') {
180→            if (lx->input[lx->pos] == '\\') { lx->pos++; if (lx->pos >= lx->input_len) break; }
181→            lx->pos++;
182→        }
183→        if (lx->pos >= lx->input_len) { emit_error(lx, "unterminated double quote"); out->kind = TOKEN_ERROR; return -2; }
184→        lx->pos--;
185→        goto done;
186→    }
187→    /* Backslash escape. */
188→    if (c == '\\') {
189→        out->kind = TOKEN_WORD;
190→        lx->pos++;
191→        if (lx->pos < lx->input_len && lx->input[lx->pos] == '\n') { lx->pos++; lx->line_no++; }
192→        else {
193→            while (lx->pos < lx->input_len) {
194→                char nc = lx->input[lx->pos];
195→                if (isspace((unsigned char)nc) || nc == ';' || nc == '|' || nc == '&' ||
196→                    nc == '>' || nc == '<' || nc == '(' || nc == ')' || nc == '!') break;
197→                lx->pos++;
198→            }
199→        }
200→        goto done;
201→    }
202→    /* ANSI-C: $'...'. */
203→    if (c == '$' && lx->pos + 1 < lx->input_len && lx->input[lx->pos+1] == '\'') {
204→        start_pos += 2;
205→        start = lx->input + start_pos;
206→        out->kind = TOKEN_WORD;
207→        out->flags |= TOKEN_FLAG_QUOTED;
208→        lx->pos += 2;
209→        while (lx->pos < lx->input_len && lx->input[lx->pos] != '\'') {
210→            if (lx->input[lx->pos] == '\\') { lx->pos++; if (lx->pos >= lx->input_len) break; }
211→            lx->pos++;
212→        }
213→        if (lx->pos >= lx->input_len) { emit_error(lx, "unterminated $' quote"); out->kind = TOKEN_ERROR; return -2; }
214→        lx->pos--;
215→        goto done;
216→    }
217→    /* Dollar-double-quote. */
218→    if (c == '$' && lx->pos + 1 < lx->input_len && lx->input[lx->pos+1] == '"') {
219→        start_pos += 2;
220→        start = lx->input + start_pos;
221→        out->kind = TOKEN_WORD;
222→        out->flags |= TOKEN_FLAG_QUOTED;
223→        lx->pos += 2;
224→        while (lx->pos < lx->input_len && lx->input[lx->pos] != '"') { lx->pos++; }
225→        if (lx->pos >= lx->input_len) { emit_error(lx, "unterminated $\" quote"); out->kind = TOKEN_ERROR; return -2; }
226→        lx->pos--;
227→        goto done;
228→    }
229→    /* Number. */
230→    if (isdigit((unsigned char)c)) {
231→        while (lx->pos < lx->input_len && isdigit((unsigned char)lx->input[lx->pos])) lx->pos++;
232→        int is_io = (lx->pos < lx->input_len && (lx->input[lx->pos] == '<' || lx->input[lx->pos] == '>'));
233→        if (is_io) { out->kind = TOKEN_IO_NUMBER; }
234→        else {
235→            out->kind = TOKEN_WORD;
236→            while (lx->pos < lx->input_len) {
237→                char nc = lx->input[lx->pos];
238→                if (isspace((unsigned char)nc) || nc == ';' || nc == '|' || nc == '&' ||
239→                    nc == '>' || nc == '<' || nc == '(' || nc == ')' || nc == '!') break;
240→                lx->pos++;
241→            }
242→        }
243→        goto done;
244→    }
245→    /* Default word / reserved word. */
246→    out->kind = TOKEN_WORD;
247→    while (lx->pos < lx->input_len) {
248→        char nc = lx->input[lx->pos];
249→        if (isspace((unsigned char)nc) || nc == ';' || nc == '|' || nc == '&' ||
250→            nc == '>' || nc == '<' || nc == '(' || nc == ')' || nc == '!') break;
251→        lx->pos++;
252→    }
253→    size_t wlen = lx->pos - start_pos;
254→    if (is_reserved_word(start, wlen, lx->ss ? lx->ss->posix_mode : 0)) {
255→        out->kind = TOKEN_RESERVED;
256→        out->flags |= TOKEN_FLAG_RESERVED;
257→    }
258→
259→done:
260→    {
261→        size_t tlen = lx->pos - start_pos;
262→        if (tlen > 0) {
263→            out->lexeme = agenc_strndup(start, tlen);
264→            out->len = tlen;
265→            if (!out->lexeme) { lx->error = 1; lx->err_msg = agenc_strdup("out of memory"); return -2; }
266→        }
267→    }
268→    if (out->kind == TOKEN_WORD || out->kind == TOKEN_RESERVED)
269→        out->flags |= TOKEN_FLAG_ALIAS_ELIGIBLE;
270→    if (out->kind == TOKEN_ERROR) { lx->error = 1; return -2; }
271→    return 0;
272→}
273→
274→/* ---- TokenRing ---- */
275→
276→TokenRing *lexer_ring_create(void)
277→{
278→    TokenRing *r = agenc_calloc(1, sizeof(TokenRing));
279→    if (!r) return NULL;
280→    r->capacity = 16;
281→    r->tokens = agenc_calloc(r->capacity, sizeof(Token));
282→    if (!r->tokens) { agenc_free(r); return NULL; }
283→    return r;
284→}
285→
286→void lexer_ring_destroy(TokenRing *r)
287→{
288→    if (!r) return;
289→    for (int i = 0; i < r->count; i++) lexer_free_token(&r->tokens[i]);
290→    agenc_free(r->tokens);
291→    if (r->err_msg) agenc_free(r->err_msg);
292→    agenc_free(r);
293→}
294→
295→void lexer_ring_reset(TokenRing *r)
296→{
297→    if (!r) return;
298→    for (int i = 0; i < r->count; i++) lexer_free_token(&r->tokens[i]);
299→    r->count = 0;
300→}
301→
302→int lexer_ring_reserve(TokenRing *r, int extra)
303→{
304→    if (!r) return -1;
305→    int n = r->count + extra;
306→    if (n > r->capacity) {
307→        int nc = r->capacity * 2 > n ? r->capacity * 2 : n;
308→        Token *nt = agenc_realloc(r->tokens, (size_t)nc * sizeof(Token));
309→        if (!nt) return -1;
310→        r->tokens = nt; r->capacity = nc;
311→    }
312→    return 0;
313→}
314→
315→int lexer_ring_append(TokenRing *r, const Token *t)
316→{
317→    if (!r || !t) return -1;
318→    if (lexer_ring_reserve(r, 1) != 0) return -1;
319→    lexer_copy_token(r, t);
320→    return 0;
321→}
322→
323→void lexer_copy_token(TokenRing *r, const Token *from)
324→{
325→    if (!r || !from) return;
326→    Token *d = &r->tokens[r->count];
327→    memset(d, 0, sizeof(*d));
328→    if (from->lexeme) { d->lexeme = agenc_strdup(from->lexeme); d->len = from->len; }
329→    d->kind = from->kind;
330→    d->loc = from->loc;
331→    d->flags = from->flags;
332→    r->count++;
333→}
