66→/* Scan the accumulated line for heredoc redirections and track
67→ * quoting/parens for completeness checking. */
68→static void reader_scan_line(Reader *r, const char *line, size_t len)
69→{
70→    int in_single = 0;
71→    int in_double = 0;
72→    int escaped = 0;
73→    int i = 0;
74→
75→    while (i < (int)len) {
76→        char c = line[i];
77→
78→        if (escaped) {
79→            escaped = 0;
80→            i++;
81→            continue;
82→        }
83→        escaped = (c == '\\');
84→
85→        if (in_single) {
86→            if (c == '\'') in_single = 0;
87→            i++;
88→            continue;
89→        }
90→
91→        if (in_double) {
92→            if (c == '"') in_double = 0;
93→            if (c == '$' && i + 1 < (int)len) {
94→                if (line[i + 1] == '(') r->paren_depth++;
95→                if (line[i + 1] == '"') in_double = 0; /* unlikely but safe */
96→            }
97→            i++;
98→            continue;
99→        }
100→
101→        if (c == '\'') {
102→            in_single = 1;
103→        } else if (c == '"') {
104→            in_double = 1;
105→        } else if (c == '(') {
106→            r->paren_depth++;
107→        } else if (c == ')') {
108→            if (r->paren_depth > 0) r->paren_depth--;
109→        } else if (c == '<' && i + 1 < (int)len) {
110→            if (line[i + 1] == '<') {
111→                if (i + 2 < (int)len && line[i + 2] == '-') {
112→                    i += 3;
113→                } else {
114→                    i += 2;
115→                }
116→                /* Skip leading whitespace after heredoc operator */
117→                while (i < (int)len && (line[i] == ' ' || line[i] == '\t'))
118→                    i++;
119→                /* Read the delimiter word */
120→                size_t start = (size_t)i;
121→                while (i < (int)len && line[i] != ' ' && line[i] != '\t' && line[i] != '\n')
122→                    i++;
123→                size_t delim_len = (size_t)i - start;
124→                if (delim_len > 0) {
125→                    r->heredoc_pending = 1;
126→                    agenc_free(r->heredoc_delim);
127→                    r->heredoc_delim = agenc_strndup(line + start, delim_len);
128→                    /* Note: quoted flag is determined during lexing */
129→                }
