/* Internal allocator wrapper so we can swap allocators later. */

void *agenc_alloc(size_t size)
{
    return malloc(size);
}

void *agenc_calloc(size_t nmemb, size_t size)
{
    return calloc(nmemb, size);
}

void *agenc_realloc(void *ptr, size_t size)
{
    return realloc(ptr, size);
}

void agenc_free(void *ptr)
