}

/* AgencStrbuf — dynamically growable string buffer. */

typedef struct {
    char *data;
    size_t len;
    size_t cap;
} AgencStrbuf;

AgencStrbuf *agenc_strbuf_create(void)
{
    AgencStrbuf *b = agenc_calloc(1, sizeof(*b));
    if (!b) return NULL;
    b->cap = 64;
    b->data = agenc_alloc(b->cap);
    if (!b->data) { agenc_free(b); return NULL; }
    b->len = 0;
    b->data[0] = '\0';
    return b;
}

void agenc_strbuf_destroy(AgencStrbuf *b)
{
    if (!b) return;
    agenc_free(b->data);
    agenc_free(b);
}

int agenc_strbuf_append(AgencStrbuf *b, const char *s, size_t n)
{
    if (!b || !s) return -1;
    if (b->len + n + 1 > b->cap) {
        size_t new_cap = agenc_max(b->cap * 2, b->len + n + 1);
        char *tmp = agenc_realloc(b->data, new_cap);
        if (!tmp) return -1;
        b->data = tmp;
        b->cap = new_cap;
    }
    memcpy(b->data + b->len, s, n);
    b->len += n;
    b->data[b->len] = '\0';
    return 0;
}

int agenc_strbuf_append_str(AgencStrbuf *b, const char *s)
{
    return agenc_strbuf_append(b, s, strlen(s));
}

const char *agenc_strbuf_get(const AgencStrbuf *b)
{
    return b ? b->data : "";
}

size_t agenc_strbuf_len(const AgencStrbuf *b)
{
    return b ? b->len : 0;
}

