int lexer_ring_append(TokenRing *r, const Token *t)
{
    if (!r || !t) return -1;
    if (lexer_ring_reserve(r, 1) != 0) return -1;
    lexer_copy_token(r, t);
    return 0;
}

void lexer_copy_token(TokenRing *r, const Token *from)
{
    if (!r || !from) return;
    Token *d = &r->tokens[r->count];
    memset(d, 0, sizeof(*d));
    if (from->lexeme) { d->lexeme = agenc_strdup(from->lexeme); d->len = from->len; }
    d->kind = from->kind;
    d->loc = from->loc;
    d->flags = from->flags;
    r->count++;
}

