#ifndef AGENC_INPUT_H
#define AGENC_INPUT_H

#include <stddef.h>
#include <stdio.h>

/*
 * Reader — stream input reader (§8.1).
 * Handles line buffering, continuation handling, and completeness
 * checking for interactive input.
 */

typedef struct {
    FILE *stream;         /* input stream */
    char *line_buf;       /* malloc'd line buffer */
    size_t line_cap;      /* current capacity of line_buf */
    size_t line_len;      /* current length */
    int line_no;          /* current line number (1-based) */
    int eof;              /* non-zero at EOF */
    int error;            /* non-zero on read error */
    int continuation;     /* non-zero if a trailing backslash was consumed */
    int quote_depth;      /* nesting depth of unclosed quotes for completeness */
    int paren_depth;      /* nesting depth of unclosed ( for completeness */
    int heredoc_pending;  /* non-zero if heredoc body needs to be collected */
    char *heredoc_delim;  /* pending here-doc delimiter (malloc'd) */
} Reader;

/* Create a new reader reading from the given FILE*. */
Reader *reader_create(FILE *stream);

/* Destroy a reader and free all resources. */
void reader_destroy(Reader *r);

/* Read one logical shell input line.
 * Handles line continuation (trailing backslash).
 * Sets *out_line to a malloc'd string (caller must free).
 * Returns:
 *   >0   — number of bytes written (not counting NUL terminator)
 *    0   — empty line
 *   -1   — EOF
 *   -2   — read error */
int reader_readline(Reader *r, char **out_line);

/* Get current line number. */
int reader_get_line_no(const Reader *r);

/* Check if the input so far constitutes a complete shell command.
 * Returns non-zero if the command is complete, zero if more input
 * is needed (incomplete quotes, unclosed parens, etc.).
 * Also sets r->heredoc_pending / r->heredoc_delim if a heredoc
 * redirection was found. */
int reader_is_complete(const Reader *r, const char *line, size_t len);

/* Expose heredoc pending state for lexer/heredoc layer (M1 parser hook). */
int reader_has_heredoc_pending(const Reader *r);
const char *reader_get_heredoc_delim(const Reader *r);

/* Return the continuation prompt string (PS2 equivalent).
 * Caller must not free the result. */
const char *reader_get_continuation_prompt(void);

#endif /* AGENC_INPUT_H */

